// API Key authentication check - timing-safe comparison
const headers = $input.first().json.headers || {};

// Case-insensitive header lookup (defense against platform normalization changes)
const headerKeys = Object.keys(headers);
const apiKeyHeader = headerKeys.find(k => k.toLowerCase() === 'x-api-key');
const providedKey = apiKeyHeader !== undefined ? headers[apiKeyHeader] : '';
const expectedKey = $env.FLOWISE_API_KEY;

// Timing-safe comparison - prevents timing attacks on API key
function timingSafeEqual(a, b) {
  if (typeof a !== 'string' || typeof b !== 'string') return false;
  const MAX_LEN = 256;

  // Include bounds check in result (constant-time, no branch)
  let result = (a.length > MAX_LEN || b.length > MAX_LEN) ? 1 : 0;
  // Constant-time comparison: always iterate MAX_LEN, use 0 for out-of-bounds
  for (let i = 0; i < MAX_LEN; i++) {
    const charA = i < a.length ? a.charCodeAt(i) : 0;
    const charB = i < b.length ? b.charCodeAt(i) : 0;
    result |= charA ^ charB;
  }
  // Include length check in constant-time result
  result |= (a.length === b.length) ? 0 : 1;
  return result === 0;
}

// CRITICAL: Always validate API key if provided, regardless of expectedKey
// This prevents fail-open vulnerability when env var is unset
// Authentication logic:
// - If server has expectedKey configured: client MUST provide matching key
// - If server has NO expectedKey configured: reject any request that provides a key (unauthorized)
// - If neither configured: allow (no auth required)
if ((expectedKey || providedKey) && !timingSafeEqual(providedKey || '', expectedKey || '')) {
  return [{ json: { valid: false, error: 'Authentication failed' } }];
}

const input = $input.first().json || {};
const chatflowId = input.chatflowId || '';
const question = input.question || '';
const sessionId = input.sessionId || '';
const stream = input.stream || false;

// === CHATFLOW_ID VALIDATION ===
if (!chatflowId) {
  return [{ json: { valid: false, error: 'Missing required field: chatflowId' } }];
}
if (typeof chatflowId !== 'string') {
  return [{ json: { valid: false, error: 'Invalid chatflowId: must be a string' } }];
}
if (chatflowId.length > 100) {
  return [{ json: { valid: false, error: 'chatflowId too long: max 100 characters' } }];
}

// === QUESTION VALIDATION ===
if (!question) {
  return [{ json: { valid: false, error: 'Missing required field: question' } }];
}
if (typeof question !== 'string') {
  return [{ json: { valid: false, error: 'Invalid question: must be a string' } }];
}
if (question.length > 32768) {
  return [{ json: { valid: false, error: 'Question too long: max 32768 characters' } }];
}

// === SESSION_ID VALIDATION ===
if (sessionId && typeof sessionId !== 'string') {
  return [{ json: { valid: false, error: 'Invalid sessionId: must be a string' } }];
}
if (sessionId && sessionId.length > 256) {
  return [{ json: { valid: false, error: 'sessionId too long: max 256 characters' } }];
}

// === STREAM VALIDATION ===
if (typeof stream !== 'boolean') {
  return [{ json: { valid: false, error: 'Invalid stream: must be a boolean' } }];
}

// === CHANNEL VALIDATION ===
const channelRaw = (input.channel || 'general').replace(/^#+/, '').replace(/[<>@&]/g, '').slice(0, 100);
if (!channelRaw.match(/^[a-zA-Z0-9_-]+$/)) {
  return [{ json: { valid: false, error: 'Invalid channel: must be alphanumeric, dash, or underscore only' } }];
}

return [{
  json: {
    valid: true,
    chatflowId: chatflowId,
    question: question,
    sessionId: sessionId,
    stream: stream,
    channel: channelRaw
  }
}];

